select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where u.id = p.owneruserid and p.id = v.postid and p.id = c.postid and p.id = pl.postid and p.id = ph.postid and c.creationdate>=timestamp '2010-07-26 19:37:03' and p.score>=-2 and p.commentcount<=18 and p.creationdate>=timestamp '2010-07-21 13:50:08' and p.creationdate<=timestamp '2014-09-11 00:53:10' and pl.creationdate<=timestamp '2014-08-05 18:27:51' and ph.creationdate>=timestamp '2010-11-27 03:38:45' and u.downvotes>=0 and u.upvotes>=0;
